SELECT cgm.id, cgm.message_id, cgm.group_id, cgm.sender_id, u.username AS sender_name, u.avatar AS sender_avatar, cgm.content_type, cgm.content, cgm.file_id, cgm.extra_data, cgm.status, cgm.mention_all, cgm.create_time, (SELECT COUNT(*) FROM chat_group_message_read WHERE message_id = cgm.message_id AND is_read = 1) AS read_count, (SELECT COUNT(*) FROM chat_group_member WHERE group_id = cgm.group_id AND leave_time IS NULL) AS total_members FROM chat_group_message cgm LEFT JOIN user u ON cgm.sender_id = u.id WHERE cgm.group_id = #{groupId} AND cgm.is_deleted = 0
AND cgm.create_time < ( SELECT create_time FROM chat_group_message WHERE message_id = #{lastMessageId} )
ORDER BY cgm.create_time DESC LIMIT #{pageSize}
